 125 | pub struct OpenAiRealtimeConnection<S = MaybeTlsStream<TcpStream>> {
 126 |     stream: WebSocketStream<S>,
 127 | }
 128 | 
 129 | impl<S> std::fmt::Debug for OpenAiRealtimeConnection<S> {
 130 |     fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 131 |         f.debug_struct("OpenAiRealtimeConnection").finish()
 132 |     }
 133 | }
 134 | 
 135 | impl<S> OpenAiRealtimeConnection<S>
 136 | where
 137 |     S: AsyncRead + AsyncWrite + Unpin,
 138 | {
 139 |     fn new(stream: WebSocketStream<S>) -> Self {
 140 |         Self { stream }
 141 |     }
 142 | 
 143 |     pub async fn send_event(&mut self, event: &Value) -> Result<()> {
 144 |         let payload = serde_json::to_string(event).context("Failed to serialize Realtime event")?;
 145 |         self.stream
 146 |             .send(WsMessage::Text(payload.into()))
 147 |             .await
 148 |             .context("Failed to send Realtime event")?;
 149 |         Ok(())
 150 |     }
 151 | 
 152 |     pub async fn recv_event(&mut self) -> Result<Option<Value>> {
 153 |         while let Some(message) = self.stream.next().await {
 154 |             let message = message.context("Realtime WebSocket receive failed")?;
 155 |             match message {
 156 |                 WsMessage::Text(text) => {
 157 |                     let event = serde_json::from_str(&text)
 158 |                         .context("Failed to parse Realtime text event")?;
 159 |                     return Ok(Some(event));
 160 |                 }
 161 |                 WsMessage::Binary(bytes) => {
 162 |                     let text = String::from_utf8(bytes.to_vec())
 163 |                         .context("Realtime binary event was not valid UTF-8")?;
 164 |                     let event = serde_json::from_str(&text)
 165 |                         .context("Failed to parse Realtime binary event")?;
 166 |                     return Ok(Some(event));
 167 |                 }
 168 |                 WsMessage::Ping(payload) => {
 169 |                     self.stream
 170 |                         .send(WsMessage::Pong(payload))
 171 |                         .await
 172 |                         .context("Failed to respond to Realtime ping")?;
 173 |                 }
 174 |                 WsMessage::Pong(_) => {}
 175 |                 WsMessage::Frame(_) => {}
 176 |                 WsMessage::Close(_) => return Ok(None),
 177 |             }
 178 |         }
 179 | 
 180 |         Ok(None)
 181 |     }
 182 | 
 183 |     pub async fn close(&mut self) -> Result<()> {
 184 |         match self.stream.send(WsMessage::Close(None)).await {
 185 |             Ok(()) => {}
 186 |             Err(WsError::ConnectionClosed) | Err(WsError::AlreadyClosed) => {}
 187 |             Err(WsError::Io(err))
 188 |                 if matches!(
 189 |                     err.kind(),
 190 |                     ErrorKind::BrokenPipe
 191 |                         | ErrorKind::ConnectionReset
 192 |                         | ErrorKind::ConnectionAborted
 193 |                         | ErrorKind::NotConnected
 194 |                 ) => {}
 195 |             Err(err) => return Err(err).context("Failed to close Realtime WebSocket"),
 196 |         }
 197 |         Ok(())
 198 |     }
 199 | }
