 271 |     /// Generate PKCE code verifier and challenge
 272 |     fn generate_pkce() -> PkcePair {
 273 |         let random_bytes: [u8; 32] = {
 274 |             let timestamp = std::time::SystemTime::now()
 275 |                 .duration_since(std::time::UNIX_EPOCH)
 276 |                 .map(|d| d.as_nanos())
 277 |                 .unwrap_or(0);
 278 | 
 279 |             let mut bytes = [0u8; 32];
 280 |             let ts_bytes = timestamp.to_le_bytes();
 281 |             let tid = std::thread::current().id();
 282 |             let tid_repr = format!("{:?}", tid);
 283 |             let tid_hash = Sha256::digest(tid_repr.as_bytes());
 284 | 
 285 |             bytes[0..8].copy_from_slice(&ts_bytes[0..8]);
 286 |             bytes[8..24].copy_from_slice(&tid_hash[0..16]);
 287 |             bytes[24..].copy_from_slice(&Sha256::digest(ts_bytes)[0..8]);
 288 |             bytes
 289 |         };
 290 |         let verifier = URL_SAFE_NO_PAD.encode(random_bytes);
 291 | 
 292 |         let mut hasher = Sha256::new();
 293 |         hasher.update(verifier.as_bytes());
 294 |         let challenge_bytes = hasher.finalize();
 295 |         let challenge = URL_SAFE_NO_PAD.encode(challenge_bytes);
 296 | 
 297 |         PkcePair {
 298 |             verifier,
 299 |             challenge,
 300 |         }
 301 |     }
