 303 |     /// Generate random state value
 304 |     fn generate_state() -> String {
 305 |         let timestamp = std::time::SystemTime::now()
 306 |             .duration_since(std::time::UNIX_EPOCH)
 307 |             .map(|d| d.as_nanos())
 308 |             .unwrap_or(0);
 309 |         let random: [u8; 8] = {
 310 |             let ptr = Box::into_raw(Box::new(timestamp)) as usize;
 311 |             let bytes = ptr.to_le_bytes();
 312 |             let mut arr = [0u8; 8];
 313 |             arr.copy_from_slice(&bytes);
 314 |             arr
 315 |         };
 316 |         format!("{:016x}{:016x}", timestamp, u64::from_le_bytes(random))
 317 |     }
