 453 |     /// Exchange authorization code for tokens using a custom redirect URI.
 454 |     pub async fn exchange_code_with_redirect_uri(
 455 |         code: &str,
 456 |         verifier: &str,
 457 |         redirect_uri: &str,
 458 |     ) -> Result<OAuthCredentials> {
 459 |         let client = Client::new();
 460 |         let form_body = format!(
 461 |             "grant_type={}&client_id={}&code={}&code_verifier={}&redirect_uri={}",
 462 |             urlencoding::encode("authorization_code"),
 463 |             CLIENT_ID,
 464 |             urlencoding::encode(code),
 465 |             urlencoding::encode(verifier),
 466 |             urlencoding::encode(redirect_uri),
 467 |         );
 468 | 
 469 |         let response = client
 470 |             .post(TOKEN_URL)
 471 |             .header("Content-Type", "application/x-www-form-urlencoded")
 472 |             .body(form_body)
 473 |             .send()
 474 |             .await
 475 |             .context("Failed to exchange authorization code")?;
 476 | 
 477 |         if !response.status().is_success() {
 478 |             let body = response.text().await.unwrap_or_default();
 479 |             anyhow::bail!("OAuth token exchange failed: {}", body);
 480 |         }
 481 | 
 482 |         #[derive(Deserialize)]
 483 |         struct TokenResponse {
 484 |             #[serde(default)]
 485 |             id_token: Option<String>,
 486 |             access_token: String,
 487 |             refresh_token: String,
 488 |             expires_in: u64,
 489 |         }
 490 | 
 491 |         let tokens: TokenResponse = response
 492 |             .json()
 493 |             .await
 494 |             .context("Failed to parse token response")?;
 495 | 
 496 |         let expires_at = std::time::SystemTime::now()
 497 |             .duration_since(std::time::UNIX_EPOCH)
 498 |             .context("System time error")?
 499 |             .as_secs()
 500 |             + tokens.expires_in;
 501 | 
 502 |         let chatgpt_account_id = tokens
 503 |             .id_token
 504 |             .as_deref()
 505 |             .and_then(Self::extract_chatgpt_account_id_from_jwt);
 506 | 
 507 |         Ok(OAuthCredentials {
 508 |             id_token: tokens.id_token,
 509 |             chatgpt_account_id,
 510 |             access_token: tokens.access_token,
 511 |             refresh_token: tokens.refresh_token,
 512 |             expires_at,
 513 |         })
 514 |     }
