 516 |     pub async fn exchange_id_token_for_api_key(id_token: &str) -> Result<String> {
 517 |         #[derive(Deserialize)]
 518 |         struct ExchangeResponse {
 519 |             access_token: String,
 520 |         }
 521 | 
 522 |         let client = Client::new();
 523 |         let form_body = format!(
 524 |             "grant_type={}&client_id={}&requested_token={}&subject_token={}&subject_token_type={}",
 525 |             urlencoding::encode("urn:ietf:params:oauth:grant-type:token-exchange"),
 526 |             urlencoding::encode(CLIENT_ID),
 527 |             urlencoding::encode("openai-api-key"),
 528 |             urlencoding::encode(id_token),
 529 |             urlencoding::encode("urn:ietf:params:oauth:token-type:id_token"),
 530 |         );
 531 | 
 532 |         let response = client
 533 |             .post(TOKEN_URL)
 534 |             .header("Content-Type", "application/x-www-form-urlencoded")
 535 |             .body(form_body)
 536 |             .send()
 537 |             .await
 538 |             .context("Failed to exchange id_token for OpenAI API key")?;
 539 | 
 540 |         let status = response.status();
 541 |         if !status.is_success() {
 542 |             let body = response.text().await.unwrap_or_default();
 543 |             anyhow::bail!("API key token exchange failed ({}): {}", status, body);
 544 |         }
 545 | 
 546 |         let payload: ExchangeResponse = response
 547 |             .json()
 548 |             .await
 549 |             .context("Failed to parse API key token exchange response")?;
 550 |         if payload.access_token.trim().is_empty() {
 551 |             anyhow::bail!("API key token exchange returned an empty access token");
 552 |         }
 553 |         Ok(payload.access_token)
 554 |     }
