 556 |     /// Refresh access token using refresh token
 557 |     async fn refresh_access_token(&self, refresh_token: &str) -> Result<OAuthCredentials> {
 558 |         let form_body = format!(
 559 |             "grant_type={}&refresh_token={}&client_id={}",
 560 |             urlencoding::encode("refresh_token"),
 561 |             urlencoding::encode(refresh_token),
 562 |             CLIENT_ID,
 563 |         );
 564 | 
 565 |         let response = self
 566 |             .client
 567 |             .post(TOKEN_URL)
 568 |             .header("Content-Type", "application/x-www-form-urlencoded")
 569 |             .body(form_body)
 570 |             .send()
 571 |             .await
 572 |             .context("Failed to refresh access token")?;
 573 | 
 574 |         if !response.status().is_success() {
 575 |             let body = response.text().await.unwrap_or_default();
 576 |             anyhow::bail!("Token refresh failed: {}", body);
 577 |         }
 578 | 
 579 |         #[derive(Deserialize)]
 580 |         struct TokenResponse {
 581 |             access_token: String,
 582 |             refresh_token: String,
 583 |             expires_in: u64,
 584 |         }
 585 | 
 586 |         let tokens: TokenResponse = response
 587 |             .json()
 588 |             .await
 589 |             .context("Failed to parse refresh response")?;
 590 | 
 591 |         let expires_at = std::time::SystemTime::now()
 592 |             .duration_since(std::time::UNIX_EPOCH)
 593 |             .context("System time error")?
 594 |             .as_secs()
 595 |             + tokens.expires_in;
 596 | 
 597 |         Ok(OAuthCredentials {
 598 |             id_token: None,
 599 |             chatgpt_account_id: self.chatgpt_account_id.clone(),
 600 |             access_token: tokens.access_token,
 601 |             refresh_token: tokens.refresh_token,
 602 |             expires_at,
 603 |         })
 604 |     }
