 606 |     /// Get a valid access token, refreshing if necessary
 607 |     async fn get_access_token(&self) -> Result<String> {
 608 |         if let Some(ref api_key) = self.static_api_key {
 609 |             return Ok(api_key.clone());
 610 |         }
 611 | 
 612 |         {
 613 |             let cache = self.cached_tokens.read().await;
 614 |             if let Some(ref tokens) = *cache
 615 |                 && tokens
 616 |                     .expires_at
 617 |                     .duration_since(std::time::Instant::now())
 618 |                     .as_secs()
 619 |                     > 300
 620 |             {
 621 |                 return Ok(tokens.access_token.clone());
 622 |             }
 623 |         }
 624 | 
 625 |         let mut cache = self.cached_tokens.write().await;
 626 | 
 627 |         let creds = if let Some(ref stored) = self.stored_credentials {
 628 |             let now = std::time::SystemTime::now()
 629 |                 .duration_since(std::time::UNIX_EPOCH)
 630 |                 .context("System time error")?
 631 |                 .as_secs();
 632 | 
 633 |             if stored.expires_at > now + 300 {
 634 |                 stored.clone()
 635 |             } else {
 636 |                 self.refresh_access_token(&stored.refresh_token).await?
 637 |             }
 638 |         } else {
 639 |             anyhow::bail!("No OAuth credentials available. Run OAuth flow first.");
 640 |         };
 641 | 
 642 |         let expires_in = creds.expires_at
 643 |             - std::time::SystemTime::now()
 644 |                 .duration_since(std::time::UNIX_EPOCH)
 645 |                 .context("System time error")?
 646 |                 .as_secs();
 647 | 
 648 |         let cached = CachedTokens {
 649 |             access_token: creds.access_token.clone(),
 650 |             refresh_token: creds.refresh_token.clone(),
 651 |             expires_at: std::time::Instant::now() + std::time::Duration::from_secs(expires_in),
 652 |         };
 653 | 
 654 |         let token = cached.access_token.clone();
 655 |         *cache = Some(cached);
 656 |         Ok(token)
 657 |     }
