 895 |     fn extract_chatgpt_account_id_from_jwt(jwt: &str) -> Option<String> {
 896 |         let payload_b64 = jwt.split('.').nth(1)?;
 897 |         let payload = URL_SAFE_NO_PAD.decode(payload_b64).ok()?;
 898 |         let value: Value = serde_json::from_slice(&payload).ok()?;
 899 | 
 900 |         value
 901 |             .get("https://api.openai.com/auth")
 902 |             .and_then(Value::as_object)
 903 |             .and_then(|auth| auth.get("chatgpt_account_id"))
 904 |             .and_then(Value::as_str)
 905 |             .map(|s| s.to_string())
 906 |             .or_else(|| {
 907 |                 value
 908 |                     .get("chatgpt_account_id")
 909 |                     .and_then(Value::as_str)
 910 |                     .map(|s| s.to_string())
 911 |             })
 912 |             .or_else(|| {
 913 |                 value
 914 |                     .get("organizations")
 915 |                     .and_then(Value::as_array)
 916 |                     .and_then(|orgs| orgs.first())
 917 |                     .and_then(|org| org.get("id"))
 918 |                     .and_then(Value::as_str)
 919 |                     .map(|s| s.to_string())
 920 |             })
 921 |     }
