1160 |     fn parse_responses_event(
1161 |         parser: &mut ResponsesSseParser,
1162 |         event: &Value,
1163 |         chunks: &mut Vec<StreamChunk>,
1164 |     ) {
1165 |         match event.get("type").and_then(Value::as_str) {
1166 |             Some("response.output_text.delta") => {
1167 |                 if let Some(delta) = event.get("delta").and_then(Value::as_str) {
1168 |                     chunks.push(StreamChunk::Text(delta.to_string()));
1169 |                 }
1170 |             }
1171 |             Some("response.output_item.added") => {
1172 |                 if let Some(item) = event.get("item") {
1173 |                     Self::record_responses_tool_item(parser, item, chunks, false);
1174 |                 }
1175 |             }
1176 |             Some("response.function_call_arguments.delta") => {
1177 |                 Self::record_responses_tool_arguments(parser, &event, chunks, false);
1178 |             }
1179 |             Some("response.function_call_arguments.done") => {
1180 |                 Self::record_responses_tool_arguments(parser, &event, chunks, true);
1181 |             }
1182 |             Some("response.output_item.done") => {
1183 |                 if let Some(item) = event.get("item")
1184 |                     && item.get("type").and_then(Value::as_str) == Some("function_call")
1185 |                     && let Some(key) = item
1186 |                         .get("id")
1187 |                         .and_then(Value::as_str)
1188 |                         .or_else(|| item.get("call_id").and_then(Value::as_str))
1189 |                 {
1190 |                     Self::record_responses_tool_item(parser, item, chunks, true);
1191 |                     Self::finish_responses_tool_call(parser, key, chunks);
1192 |                 }
1193 |             }
1194 |             Some("response.completed") | Some("response.done") => {
1195 |                 if let Some(output) = event
1196 |                     .get("response")
1197 |                     .and_then(|response| response.get("output"))
1198 |                     .and_then(Value::as_array)
1199 |                 {
1200 |                     for item in output {
1201 |                         if item.get("type").and_then(Value::as_str) == Some("function_call")
1202 |                             && let Some(key) = item
1203 |                                 .get("id")
1204 |                                 .and_then(Value::as_str)
1205 |                                 .or_else(|| item.get("call_id").and_then(Value::as_str))
1206 |                         {
1207 |                             Self::record_responses_tool_item(parser, item, chunks, true);
1208 |                             Self::finish_responses_tool_call(parser, key, chunks);
1209 |                         }
1210 |                     }
1211 |                 }
1212 |                 let failed_message = event
1213 |                     .get("response")
1214 |                     .and_then(|response| response.get("status"))
1215 |                     .and_then(Value::as_str)
1216 |                     .filter(|status| matches!(*status, "failed" | "cancelled" | "incomplete"))
1217 |                     .map(|_| {
1218 |                         event
1219 |                             .get("response")
1220 |                             .and_then(|response| response.get("error"))
1221 |                             .and_then(|error| error.get("message"))
1222 |                             .and_then(Value::as_str)
1223 |                             .unwrap_or("Response failed")
1224 |                             .to_string()
1225 |                     });
1226 |                 if let Some(message) = failed_message {
1227 |                     chunks.push(StreamChunk::Error(message));
1228 |                     return;
1229 |                 }
1230 |                 let usage = event
1231 |                     .get("response")
1232 |                     .and_then(|response| response.get("usage"))
1233 |                     .map(|usage| Self::parse_responses_usage(Some(usage)));
1234 |                 chunks.push(StreamChunk::Done { usage });
1235 |             }
1236 |             Some("response.failed") => {
1237 |                 let message = event
1238 |                     .get("response")
1239 |                     .and_then(|response| response.get("error"))
1240 |                     .and_then(|error| error.get("message"))
1241 |                     .or_else(|| event.get("error").and_then(|error| error.get("message")))
1242 |                     .and_then(Value::as_str)
1243 |                     .unwrap_or("Response failed")
1244 |                     .to_string();
1245 |                 chunks.push(StreamChunk::Error(message));
1246 |             }
1247 |             Some("error") => {
1248 |                 let message = event
1249 |                     .get("error")
1250 |                     .and_then(|error| error.get("message"))
1251 |                     .or_else(|| event.get("message"))
1252 |                     .and_then(Value::as_str)
1253 |                     .unwrap_or("Realtime error")
1254 |                     .to_string();
1255 |                 chunks.push(StreamChunk::Error(message));
1256 |             }
1257 |             _ => {}
1258 |         }
1259 |     }
