1261 |     fn parse_responses_sse_event(
1262 |         parser: &mut ResponsesSseParser,
1263 |         data: &str,
1264 |         chunks: &mut Vec<StreamChunk>,
1265 |     ) {
1266 |         if data == "[DONE]" {
1267 |             chunks.push(StreamChunk::Done { usage: None });
1268 |             return;
1269 |         }
1270 | 
1271 |         let Ok(event): Result<Value, _> = serde_json::from_str(data) else {
1272 |             return;
1273 |         };
1274 | 
1275 |         Self::parse_responses_event(parser, &event, chunks);
1276 |     }
