1278 |     fn record_responses_tool_item(
1279 |         parser: &mut ResponsesSseParser,
1280 |         item: &Value,
1281 |         chunks: &mut Vec<StreamChunk>,
1282 |         include_arguments: bool,
1283 |     ) -> Option<String> {
1284 |         if item.get("type").and_then(Value::as_str) != Some("function_call") {
1285 |             return None;
1286 |         }
1287 | 
1288 |         let key = item
1289 |             .get("id")
1290 |             .and_then(Value::as_str)
1291 |             .or_else(|| item.get("call_id").and_then(Value::as_str))?;
1292 |         let call_id = item
1293 |             .get("call_id")
1294 |             .and_then(Value::as_str)
1295 |             .or_else(|| item.get("id").and_then(Value::as_str))?
1296 |             .to_string();
1297 |         let name = item.get("name").and_then(Value::as_str).map(str::to_string);
1298 |         let arguments = if include_arguments {
1299 |             Self::extract_json_string(item.get("arguments"))
1300 |         } else {
1301 |             None
1302 |         };
1303 | 
1304 |         let state = parser
1305 |             .tools
1306 |             .entry(key.to_string())
1307 |             .or_insert_with(|| ResponsesToolState {
1308 |                 call_id: call_id.clone(),
1309 |                 ..ResponsesToolState::default()
1310 |             });
1311 |         if state.call_id.is_empty() {
1312 |             state.call_id = call_id.clone();
1313 |         }
1314 |         if state.name.is_none() {
1315 |             state.name = name;
1316 |         }
1317 |         if !state.started
1318 |             && let Some(name) = state.name.clone()
1319 |         {
1320 |             chunks.push(StreamChunk::ToolCallStart {
1321 |                 id: state.call_id.clone(),
1322 |                 name,
1323 |             });
1324 |             state.started = true;
1325 |         }
1326 |         if let Some(arguments) = arguments {
1327 |             Self::emit_missing_responses_tool_arguments(state, arguments, chunks);
1328 |         }
1329 | 
1330 |         Some(state.call_id.clone())
1331 |     }
