1333 |     fn record_responses_tool_arguments(
1334 |         parser: &mut ResponsesSseParser,
1335 |         event: &Value,
1336 |         chunks: &mut Vec<StreamChunk>,
1337 |         use_final_arguments: bool,
1338 |     ) {
1339 |         let key = event
1340 |             .get("item_id")
1341 |             .and_then(Value::as_str)
1342 |             .or_else(|| event.get("call_id").and_then(Value::as_str));
1343 |         let Some(key) = key else {
1344 |             return;
1345 |         };
1346 | 
1347 |         let fallback_call_id = event
1348 |             .get("call_id")
1349 |             .and_then(Value::as_str)
1350 |             .unwrap_or(key)
1351 |             .to_string();
1352 |         let state = parser
1353 |             .tools
1354 |             .entry(key.to_string())
1355 |             .or_insert_with(|| ResponsesToolState {
1356 |                 call_id: fallback_call_id.clone(),
1357 |                 ..ResponsesToolState::default()
1358 |             });
1359 |         if state.call_id.is_empty() {
1360 |             state.call_id = fallback_call_id;
1361 |         }
1362 | 
1363 |         if !state.started
1364 |             && let Some(name) = event.get("name").and_then(Value::as_str)
1365 |         {
1366 |             state.name = Some(name.to_string());
1367 |             chunks.push(StreamChunk::ToolCallStart {
1368 |                 id: state.call_id.clone(),
1369 |                 name: name.to_string(),
1370 |             });
1371 |             state.started = true;
1372 |         }
1373 | 
1374 |         let arguments = if use_final_arguments {
1375 |             Self::extract_json_string(event.get("arguments")).or_else(|| {
1376 |                 event
1377 |                     .get("delta")
1378 |                     .and_then(Value::as_str)
1379 |                     .map(str::to_string)
1380 |             })
1381 |         } else {
1382 |             event
1383 |                 .get("delta")
1384 |                 .and_then(Value::as_str)
1385 |                 .map(str::to_string)
1386 |         };
1387 | 
1388 |         if let Some(arguments) = arguments {
1389 |             Self::emit_missing_responses_tool_arguments(state, arguments, chunks);
1390 |         }
1391 |     }
