1393 |     fn emit_missing_responses_tool_arguments(
1394 |         state: &mut ResponsesToolState,
1395 |         arguments: String,
1396 |         chunks: &mut Vec<StreamChunk>,
1397 |     ) {
1398 |         let delta = if arguments.starts_with(&state.emitted_arguments) {
1399 |             arguments[state.emitted_arguments.len()..].to_string()
1400 |         } else if state.emitted_arguments.is_empty() {
1401 |             arguments.clone()
1402 |         } else if arguments == state.emitted_arguments {
1403 |             String::new()
1404 |         } else {
1405 |             arguments.clone()
1406 |         };
1407 | 
1408 |         if !delta.is_empty() {
1409 |             chunks.push(StreamChunk::ToolCallDelta {
1410 |                 id: state.call_id.clone(),
1411 |                 arguments_delta: delta.clone(),
1412 |             });
1413 |             state.emitted_arguments.push_str(&delta);
1414 |         }
1415 |     }
