1417 |     fn parse_responses_sse_bytes(
1418 |         parser: &mut ResponsesSseParser,
1419 |         bytes: &[u8],
1420 |     ) -> Vec<StreamChunk> {
1421 |         parser.line_buffer.push_str(&String::from_utf8_lossy(bytes));
1422 |         let mut chunks = Vec::new();
1423 | 
1424 |         while let Some(line_end) = parser.line_buffer.find('\n') {
1425 |             let mut line = parser.line_buffer[..line_end].to_string();
1426 |             parser.line_buffer.drain(..=line_end);
1427 | 
1428 |             if line.ends_with('\r') {
1429 |                 line.pop();
1430 |             }
1431 | 
1432 |             if line.is_empty() {
1433 |                 if !parser.event_data_lines.is_empty() {
1434 |                     let data = parser.event_data_lines.join("\n");
1435 |                     parser.event_data_lines.clear();
1436 |                     Self::parse_responses_sse_event(parser, &data, &mut chunks);
1437 |                 }
1438 |                 continue;
1439 |             }
1440 | 
1441 |             if let Some(data) = line.strip_prefix("data:") {
1442 |                 let data = data.strip_prefix(' ').unwrap_or(data);
1443 |                 parser.event_data_lines.push(data.to_string());
1444 |             }
1445 |         }
1446 | 
1447 |         chunks
1448 |     }
1449 | 
1450 |     fn finish_responses_sse_parser(parser: &mut ResponsesSseParser) -> Vec<StreamChunk> {
1451 |         let mut chunks = Vec::new();
1452 | 
1453 |         if !parser.line_buffer.is_empty() {
1454 |             let mut line = std::mem::take(&mut parser.line_buffer);
1455 |             if line.ends_with('\r') {
1456 |                 line.pop();
1457 |             }
1458 |             if let Some(data) = line.strip_prefix("data:") {
1459 |                 let data = data.strip_prefix(' ').unwrap_or(data);
1460 |                 parser.event_data_lines.push(data.to_string());
1461 |             }
1462 |         }
1463 | 
1464 |         if !parser.event_data_lines.is_empty() {
1465 |             let data = parser.event_data_lines.join("\n");
1466 |             parser.event_data_lines.clear();
1467 |             Self::parse_responses_sse_event(parser, &data, &mut chunks);
1468 |         }
1469 | 
1470 |         chunks
1471 |     }
