1495 |     async fn collect_stream_completion(
1496 |         mut stream: BoxStream<'static, StreamChunk>,
1497 |     ) -> Result<CompletionResponse> {
1498 |         #[derive(Default)]
1499 |         struct ToolAccumulator {
1500 |             id: String,
1501 |             name: String,
1502 |             arguments: String,
1503 |         }
1504 | 
1505 |         let mut text = String::new();
1506 |         let mut tools = Vec::<ToolAccumulator>::new();
1507 |         let mut tool_index_by_id = HashMap::<String, usize>::new();
1508 |         let mut usage = Usage::default();
1509 | 
1510 |         while let Some(chunk) = stream.next().await {
1511 |             match chunk {
1512 |                 StreamChunk::Text(delta) => text.push_str(&delta),
1513 |                 StreamChunk::ToolCallStart { id, name } => {
1514 |                     let next_idx = tools.len();
1515 |                     let idx = *tool_index_by_id.entry(id.clone()).or_insert(next_idx);
1516 |                     if idx == next_idx {
1517 |                         tools.push(ToolAccumulator {
1518 |                             id,
1519 |                             name,
1520 |                             arguments: String::new(),
1521 |                         });
1522 |                     } else if tools[idx].name == "tool" {
1523 |                         tools[idx].name = name;
1524 |                     }
1525 |                 }
1526 |                 StreamChunk::ToolCallDelta {
1527 |                     id,
1528 |                     arguments_delta,
1529 |                 } => {
1530 |                     if let Some(idx) = tool_index_by_id.get(&id).copied() {
1531 |                         tools[idx].arguments.push_str(&arguments_delta);
1532 |                     } else {
1533 |                         let idx = tools.len();
1534 |                         tool_index_by_id.insert(id.clone(), idx);
1535 |                         tools.push(ToolAccumulator {
1536 |                             id,
1537 |                             name: "tool".to_string(),
1538 |                             arguments: arguments_delta,
1539 |                         });
1540 |                     }
1541 |                 }
1542 |                 StreamChunk::ToolCallEnd { .. } => {}
1543 |                 StreamChunk::Done { usage: done_usage } => {
1544 |                     if let Some(done_usage) = done_usage {
1545 |                         usage = done_usage;
1546 |                     }
1547 |                 }
1548 |                 StreamChunk::Error(message) => anyhow::bail!(message),
1549 |             }
1550 |         }
1551 | 
1552 |         let mut content = Vec::new();
1553 |         if !text.is_empty() {
1554 |             content.push(ContentPart::Text { text });
1555 |         }
1556 |         for tool in tools {
1557 |             content.push(ContentPart::ToolCall {
1558 |                 id: tool.id,
1559 |                 name: tool.name,
1560 |                 arguments: tool.arguments,
1561 |                 thought_signature: None,
1562 |             });
1563 |         }
1564 | 
1565 |         let finish_reason = if content
1566 |             .iter()
1567 |             .any(|part| matches!(part, ContentPart::ToolCall { .. }))
1568 |         {
1569 |             FinishReason::ToolCalls
1570 |         } else {
1571 |             FinishReason::Stop
1572 |         };
1573 | 
1574 |         Ok(CompletionResponse {
1575 |             message: Message {
1576 |                 role: Role::Assistant,
1577 |                 content,
1578 |             },
1579 |             usage,
1580 |             finish_reason,
1581 |         })
1582 |     }
