1641 |     async fn complete_stream_with_chatgpt_http_responses(
1642 |         &self,
1643 |         request: CompletionRequest,
1644 |         access_token: String,
1645 |         account_id: String,
1646 |     ) -> Result<BoxStream<'static, StreamChunk>> {
1647 |         let (model, reasoning_effort) = Self::resolve_model_and_reasoning_effort(&request.model);
1648 |         let instructions = Self::extract_responses_instructions(&request.messages);
1649 |         let input = Self::convert_messages_to_responses_input(&request.messages);
1650 |         let tools = Self::convert_responses_tools(&request.tools);
1651 | 
1652 |         let mut body = json!({
1653 |             "model": model,
1654 |             "instructions": instructions,
1655 |             "input": input,
1656 |             "stream": true,
1657 |             "store": false,
1658 |             "tool_choice": "auto",
1659 |             "parallel_tool_calls": true,
1660 |         });
1661 | 
1662 |         if !tools.is_empty() {
1663 |             body["tools"] = json!(tools);
1664 |         }
1665 |         if let Some(level) = reasoning_effort {
1666 |             body["reasoning"] = json!({ "effort": level.as_str() });
1667 |         }
1668 | 
1669 |         tracing::info!(
1670 |             backend = "chatgpt-codex-responses-http",
1671 |             instructions_len = body
1672 |                 .get("instructions")
1673 |                 .and_then(|v| v.as_str())
1674 |                 .map(str::len)
1675 |                 .unwrap_or(0),
1676 |             input_items = body
1677 |                 .get("input")
1678 |                 .and_then(|v| v.as_array())
1679 |                 .map(Vec::len)
1680 |                 .unwrap_or(0),
1681 |             has_tools = !tools.is_empty(),
1682 |             "Sending HTTP responses request"
1683 |         );
1684 | 
1685 |         let response = self
1686 |             .client
1687 |             .post(format!("{}/responses", CHATGPT_CODEX_API_URL))
1688 |             .header("Authorization", format!("Bearer {}", access_token))
1689 |             .header("chatgpt-account-id", account_id)
1690 |             .header("Content-Type", "application/json")
1691 |             .json(&body)
1692 |             .send()
1693 |             .await
1694 |             .context("Failed to send streaming request to ChatGPT Codex backend")?;
1695 | 
1696 |         let status = response.status();
1697 |         if !status.is_success() {
1698 |             let body = response.text().await.unwrap_or_default();
1699 |             anyhow::bail!(Self::format_openai_api_error(status, &body, &request.model));
1700 |         }
1701 | 
1702 |         let stream = async_stream::stream! {
1703 |             let mut parser = ResponsesSseParser::default();
1704 |             let mut byte_stream = response.bytes_stream();
1705 | 
1706 |             while let Some(result) = byte_stream.next().await {
1707 |                 match result {
1708 |                     Ok(bytes) => {
1709 |                         for chunk in Self::parse_responses_sse_bytes(&mut parser, &bytes) {
1710 |                             yield chunk;
1711 |                         }
1712 |                     }
1713 |                     Err(error) => yield StreamChunk::Error(error.to_string()),
1714 |                 }
1715 |             }
1716 | 
1717 |             for chunk in Self::finish_responses_sse_parser(&mut parser) {
1718 |                 yield chunk;
1719 |             }
1720 |         };
1721 | 
1722 |         Ok(Box::pin(stream))
1723 |     }
