1845 |                 ws_backend,
1846 |             )
1847 |             .await?;
1848 | 
1849 |         let stream = async_stream::stream! {
1850 |             let mut connection = connection;
1851 |             let mut parser = ResponsesSseParser::default();
1852 |             if let Err(error) = connection.send_event(&body).await {
1853 |                 yield StreamChunk::Error(error.to_string());
1854 |                 let _ = connection.close().await;
1855 |                 return;
1856 |             }
1857 | 
1858 |             let mut saw_terminal = false;
1859 |             loop {
1860 |                 match connection.recv_event().await {
1861 |                     Ok(Some(event)) => {
1862 |                         let mut chunks = Vec::new();
1863 |                         Self::parse_responses_event(&mut parser, &event, &mut chunks);
1864 |                         for chunk in chunks {
1865 |                             if matches!(chunk, StreamChunk::Done { .. } | StreamChunk::Error(_)) {
1866 |                                 saw_terminal = true;
1867 |                             }
1868 |                             yield chunk;
1869 |                         }
1870 |                         if saw_terminal {
1871 |                             break;
1872 |                         }
1873 |                     }
1874 |                     Ok(None) => {
1875 |                         if !saw_terminal {
1876 |                             yield StreamChunk::Error("Realtime WebSocket closed before response completion".to_string());
1877 |                         }
1878 |                         break;
1879 |                     }
1880 |                     Err(error) => {
1881 |                         yield StreamChunk::Error(error.to_string());
1882 |                         break;
1883 |                     }
1884 |                 }
1885 |             }
1886 | 
1887 |             let _ = connection.close().await;
1888 |         };
1889 | 
1890 |         Ok(Box::pin(stream))
1891 |     }
1892 | }
