 321 |     /// Resolve a model string to a provider.
 322 |     ///
 323 |     /// Accepts model strings in formats:
 324 |     /// - "provider/model" (e.g., "openai/gpt-4o")
 325 |     /// - "model" (uses first available provider)
 326 |     ///
 327 |     /// Returns the provider and the model name to use.
 328 |     pub fn resolve_model(&self, model_str: &str) -> Result<(Arc<dyn Provider>, String)> {
 329 |         let (provider_name, model) = parse_model_string(model_str);
 330 | 
 331 |         if let Some(provider_name) = provider_name {
 332 |             // Normalize provider aliases
 333 |             let normalized = match provider_name {
 334 |                 "local-cuda" | "localcuda" => "local_cuda",
 335 |                 "zhipuai" => "zai",
 336 |                 other => other,
 337 |             };
 338 | 
 339 |             let provider = self.providers.get(normalized).cloned().ok_or_else(|| {
 340 |                 anyhow::anyhow!(
 341 |                     "Provider '{}' not found. Available: {:?}",
 342 |                     normalized,
 343 |                     self.list()
 344 |                 )
 345 |             })?;
 346 |             Ok((provider, model.to_string()))
 347 |         } else {
 348 |             // No provider specified - use first available
 349 |             let first_provider = self
 350 |                 .providers
 351 |                 .values()
 352 |                 .next()
 353 |                 .ok_or_else(|| anyhow::anyhow!("No providers available in registry"))?;
 354 |             Ok((first_provider.clone(), model_str.to_string()))
 355 |         }
 356 |     }
