 437 |     /// Initialize providers from HashiCorp Vault with configurable environment variable fallback.
 438 |     ///
 439 |     /// This loads API keys from Vault and creates providers dynamically.
 440 |     /// Supports OpenAI-compatible providers via base_url.
 441 |     ///
 442 |     /// # Security Model & Environment Variable Fallback
 443 |     ///
 444 |     /// By default, this function attempts to load credentials from Vault first. If a provider
 445 |     /// is not configured in Vault, it falls back to checking environment variables for common
 446 |     /// providers (OpenAI, Anthropic, Google, OpenRouter). This fallback behavior is intended
 447 |     /// for local development and testing convenience.
 448 |     ///
 449 |     /// **Security Consideration**: In production or security-conscious deployments, environment
 450 |     /// variable fallback may be undesirable because:
 451 |     /// - Environment variables can be leaked via logs, process listings, or container inspection
 452 |     /// - They may persist in shell history or configuration files
 453 |     /// - Multiple processes share the same environment, increasing attack surface
 454 |     ///
 455 |     /// # Disabling Environment Variable Fallback
 456 |     ///
 457 |     /// Set the environment variable `CODETETHER_DISABLE_ENV_FALLBACK=1` to disable all
 458 |     /// environment variable fallback for provider credentials. When set:
 459 |     /// - Only Vault-configured providers will be available
 460 |     /// - The `register_env_fallbacks()` step is skipped entirely
 461 |     /// - Bedrock auto-detection from `AWS_*` environment variables is also disabled
 462 |     ///
 463 |     /// ```bash
 464 |     /// # Security-hardened deployment (no env var fallback)
 465 |     /// export CODETETHER_DISABLE_ENV_FALLBACK=1
 466 |     /// codetether serve
 467 |     /// ```
 468 |     ///
 469 |     /// # Fallback Order
 470 |     ///
 471 |     /// 1. **Vault secrets** (primary source): `secret/data/codetether/providers/<provider_id>`
 472 |     /// 2. **Bedrock auto-detection** (if not in Vault): Reads `AWS_ACCESS_KEY_ID`, `AWS_SECRET_ACCESS_KEY`
 473 |     /// 3. **Environment variable fallback** (if enabled):
 474 |     ///    - `OPENAI_API_KEY` → OpenAI provider
 475 |     ///    - `ANTHROPIC_API_KEY` → Anthropic provider
 476 |     ///    - `GOOGLE_API_KEY` → Google provider
 477 |     ///    - `OPENROUTER_API_KEY` → OpenRouter provider
 478 |     ///
 479 |     /// # Default Behavior
 480 |     ///
 481 |     /// The default (without `CODETETHER_DISABLE_ENV_FALLBACK`) allows environment variable
 482 |     /// fallback for backward compatibility and developer convenience. This default is
 483 |     /// intentionally permissive to support local development workflows where Vault may
 484 |     /// not be available.
 485 |     ///
 486 |     /// # See Also
 487 |     ///
 488 |     /// - `register_env_fallbacks()` for the list of supported environment variables
 489 |     /// - `src/secrets/mod.rs` for Vault configuration details
 490 |     /// - `AGENTS.md` for security best practices regarding secrets management
 491 |     pub async fn from_vault() -> Result<Self> {
 492 |         let mut registry = Self::new();
 493 |         let disable_env_fallback = std::env::var("CODETETHER_DISABLE_ENV_FALLBACK")
 494 |             .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
 495 |             .unwrap_or(false);
 496 | 
 497 |         if let Some(manager) = crate::secrets::secrets_manager() {
 498 |             // List all configured providers from Vault
 499 |             let providers = manager.list_configured_providers().await?;
 500 |             tracing::info!("Found {} providers configured in Vault", providers.len());
 501 | 
 502 |             for provider_id in providers {
 503 |                 let secrets = match manager.get_provider_secrets(&provider_id).await? {
 504 |                     Some(s) => s,
 505 |                     None => continue,
 506 |                 };
 507 | 
 508 |                 // Handle Bedrock before api_key extraction since it can use
 509 |                 // AWS IAM credentials instead of an API key.
 510 |                 if matches!(provider_id.as_str(), "bedrock" | "aws-bedrock") {
 511 |                     let region = secrets
 512 |                         .extra
 513 |                         .get("region")
 514 |                         .and_then(|v| v.as_str())
 515 |                         .unwrap_or("us-east-1")
 516 |                         .to_string();
 517 | 
 518 |                     // Prefer SigV4 if AWS credentials are in Vault
 519 |                     let aws_key_id = secrets
 520 |                         .extra
 521 |                         .get("aws_access_key_id")
 522 |                         .and_then(|v| v.as_str());
 523 |                     let aws_secret = secrets
 524 |                         .extra
 525 |                         .get("aws_secret_access_key")
 526 |                         .and_then(|v| v.as_str());
 527 | 
